# src/session_store.py
import json
import os
from pathlib import Path
from datetime import datetime, date
from typing import List, Dict, Any
import uuid

class SessionStore:
    def __init__(self, storage_path: Path, daily_goal: int = 120):
        self.storage_path = storage_path
        self.daily_goal = daily_goal
        self._ensure_storage()

    def _ensure_storage(self) -> None:
        self.storage_path.parent.mkdir(parents=True, exist_ok=True)
        if not self.storage_path.exists():
            self._save_data([])

    def _load_data(self) -> List[Dict[str, Any]]:
        try:
            with open(self.storage_path, "r") as f:
                return json.load(f)
        except (json.JSONDecodeError, FileNotFoundError):
            return []

    def _save_data(self, data: List[Dict[str, Any]]) -> None:
        with open(self.storage_path, "w") as f:
            json.dump(data, f, indent=2)

    def list_sessions(self) -> List[Dict[str, Any]]:
        sessions = self._load_data()
        return sorted(sessions, key=lambda x: x["created_at"], reverse=True)

    def add_session(self, topic: str, minutes: int, mood: str, notes: str) -> str:
        if minutes <= 0:
            raise ValueError("Minutes must be positive.")

        sessions = self._load_data()
        session_id = str(uuid.uuid4())
        new_session = {
            "session_id": session_id,
            "topic": topic.strip() or "General Study",
            "minutes": minutes,
            "mood": mood,
            "notes": notes,
            "created_at": datetime.now().isoformat()
        }
        sessions.append(new_session)
        self._save_data(sessions)
        return session_id

    def delete_session(self, session_id: str) -> None:
        sessions = self._load_data()
        filtered = [s for s in sessions if s["session_id"] != session_id]
        self._save_data(filtered)

    def summarize(self) -> Dict[str, Any]:
        sessions = self._load_data()
        today_str = date.today().isoformat()

        total_mins = sum(s["minutes"] for s in sessions)
        today_mins = sum(s["minutes"] for s in sessions if s["created_at"].startswith(today_str))

        # Simple Topic Logic
        topics: Dict[str, int] = {}
        for s in sessions:
            topics[s["topic"]] = topics.get(s["topic"], 0) + s["minutes"]
        fav_topic = max(topics, key=topics.get) if topics else "None"

        # Simple Streak Logic (Days with at least one session)
        dates = sorted({s["created_at"][:10] for s in sessions}, reverse=True)
        streak = 0
        current_check = date.today()
        for d_str in dates:
            d = date.fromisoformat(d_str)
            if d == current_check:
                streak += 1
                current_check = date.fromordinal(current_check.toordinal() - 1)
            elif d > current_check:
                continue
            else:
                break

        achievements = []
        if streak >= 3: achievements.append("3-Day Streak 🔥")
        if total_mins >= 600: achievements.append("10-Hour Master 🏆")
        if today_mins >= self.daily_goal: achievements.append("Goal Crusher 🎯")

        suggestion = "Time to hit the books!" if today_mins < self.daily_goal else "Goal reached! Great job."

        return {
            "total_minutes": total_mins,
            "today_minutes": today_mins,
            "daily_goal": self.daily_goal,
            "streak_days": streak,
            "favorite_topic": fav_topic,
            "achievements": achievements,
            "suggestion": suggestion
        }

    def seed_demo_data(self) -> None:
        demo_sessions = [
            {"session_id": "d1", "topic": "Python", "minutes": 45, "mood": "Happy", "notes": "Learned decorators", "created_at": date.today().isoformat() + "T10:00:00"},
            {"session_id": "d2", "topic": "Flask", "minutes": 90, "mood": "Focused", "notes": "Routing", "created_at": date.today().isoformat() + "T14:00:00"},
        ]
        self._save_data(demo_sessions)
