# src/web_app.py
import os
from pathlib import Path
from flask import Flask, render_template, request, redirect, url_for, flash
from .session_store import SessionStore
from .quest_engine import generate_daily_quests

app = Flask(__name__)
app.secret_key = "demo-secret-key"

# Configuration
DEFAULT_STORE = Path.home() / ".study_tracker" / "sessions.json"
STORE_PATH = Path(os.getenv("STUDY_TRACKER_STORE", str(DEFAULT_STORE)))
DAILY_GOAL = int(os.getenv("STUDY_TRACKER_DAILY_GOAL", "120"))

store = SessionStore(STORE_PATH, daily_goal=DAILY_GOAL)

@app.route("/")
def dashboard():
    summary = store.summarize()
    sessions = store.list_sessions()[:5]
    quests = generate_daily_quests(summary["today_minutes"], summary["daily_goal"])

    progress_percent = min(100, int((summary["today_minutes"] / summary["daily_goal"]) * 100))

    return render_template(
        "dashboard.html",
        summary=summary,
        sessions=sessions,
        quests=quests,
        progress_percent=progress_percent
    )

@app.route("/sessions")
def list_sessions():
    sessions = store.list_sessions()
    return render_template("sessions.html", sessions=sessions)

@app.route("/sessions/add", methods=["GET", "POST"])
def add_session():
    if request.method == "POST":
        try:
            topic = request.form.get("topic", "")
            minutes = int(request.form.get("minutes", 0))
            mood = request.form.get("mood", "")
            notes = request.form.get("notes", "")

            store.add_session(topic, minutes, mood, notes)
            return redirect(url_for("dashboard"))
        except ValueError as e:
            flash(str(e))
            return render_template("add_session.html"), 400

    return render_template("add_session.html")

@app.route("/sessions/delete/<session_id>", methods=["POST"])
def delete_session(session_id: str):
    store.delete_session(session_id)
    return redirect(url_for("list_sessions"))

@app.route("/demo-reset", methods=["POST"])
def demo_reset():
    store.seed_demo_data()
    return redirect(url_for("dashboard"))

if __name__ == "__main__":
    app.run(debug=True, port=5000)
